import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

const ArtisanProfil = () => {
    const { id } = useParams();
    const [artisan, setArtisan] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        axios.get(`http://localhost:5000/api/artisans/${id}`)
            .then(res => {
                setArtisan(res.data);
                setLoading(false);
            })
            .catch(err => {
                console.error("Erreur lors du chargement du profil:", err);
                setLoading(false);
            });
    }, [id]);

    if (loading) return <div className="text-center py-5">Chargement du profil...</div>;
    if (!artisan) return <div className="alert alert-danger">Artisan introuvable.</div>;

    return (
        <div className="container py-5">
            <div className="card shadow-sm border-0 p-4">
                <div className="row">
                    <div className="col-md-4 text-center">
                        <img
                            src={require(`../assets/artisans/${artisan.id}.jpg`)}
                            alt={artisan.name}
                            className="img-fluid rounded shadow"
                        />
                    </div>
                    <div className="col-md-8">
                        <h1 className="fw-bold">{artisan.name}</h1>
                        <h4 className="text-primary mb-3">
                            {artisan.Specialty ? artisan.Specialty.name : 'Artisan'}
                        </h4>

                        <div className="mb-3">
                            <span className="badge bg-warning text-dark fs-6">
                                ★ {artisan.note} / 5
                            </span>
                            <span className="ms-3 text-muted">📍 {artisan.location}</span>
                        </div>

                        <hr />

                        <h5>À propos</h5>
                        <p className="text-secondary" style={{ lineHeight: '1.6' }}>
                            {artisan.about || "Aucune description disponible pour cet artisan."}
                        </p>

                        <div className="mt-4">
                            <h6>Contact & Informations</h6>
                            <p className="mb-1">📧 <strong>Email :</strong> {artisan.email}</p>
                            {artisan.website && (
                                <p>🌐 <strong>Site web :</strong> <a href={artisan.website} target="_blank" rel="noreferrer">{artisan.website}</a></p>
                            )}
                        </div>

                        <div className="mt-4">
                            <button className="btn btn-primary px-5 rounded-pill" style={{ backgroundColor: '#0082c3' }}>
                                Contacter l'artisan
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ArtisanProfil;
